const { google } = require('googleapis');
const fs = require('fs');
const path = require('path');
const multer = require('multer');

const HEADER_IMG_B64 = '';

const buildHtmlEmail = (plainText) => {
  const escaped = plainText
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

  const lines = escaped.split('\n');
  let rows = '';
  let inList = false;

  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith('- ')) {
      const parts = trimmed.slice(2).split(':');
      const label = parts[0]?.trim() || '';
      const value = parts.slice(1).join(':').trim();
      rows += `
        <tr>
          <td style="padding:11px 20px;font-size:12px;font-weight:bold;color:#7a6555;text-transform:uppercase;letter-spacing:0.06em;border-bottom:1px solid #ede8e0;width:45%;">${label}</td>
          <td style="padding:11px 20px;font-size:14px;color:#3d3228;border-bottom:1px solid #ede8e0;text-align:right;">${value}</td>
        </tr>`;
      inList = true;
    } else {
      inList = false;
    }
  }

  const nonListLines = lines.filter(l => !l.trim().startsWith('- ')).join('\n');
  const paragraphs = nonListLines
    .split('\n\n')
    .map(p => p.trim())
    .filter(Boolean)
    .map(p => {
      const lineBreaked = p.replace(/\n/g, '<br/>');
      return `<p style="margin:0 0 16px;font-size:15px;color:#3d3228;line-height:1.7;">${lineBreaked}</p>`;
    })
    .join('');

  return `<!DOCTYPE html>
<html>
<body style="margin:0;padding:0;background:#f5f5f0;font-family:Georgia,serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f5f5f0;padding:32px 0;">
    <tr><td align="center">
      <table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,0.08);">
        <tr>
          <td style="background:#f0ede6;padding:0;text-align:center;">
            <img src="data:image/png;base64," alt="Matthew &amp; Melka" style="width:100%;max-width:600px;display:block;" />
          </td>
        </tr>
        <tr>
          <td style="padding:40px 48px 8px;">
            ${paragraphs.split('</p>').slice(0, 2).join('</p>')}${paragraphs.endsWith('</p>') ? '' : ''}
          </td>
        </tr>
        ${rows ? `<tr><td style="padding:0 48px 28px;"><table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #ede8e0;border-radius:6px;overflow:hidden;">${rows}</table></td></tr>` : ''}
        <tr>
          <td style="padding:0 48px 40px;">
            ${paragraphs.split('</p>').slice(2).join('</p>')}
          </td>
        </tr>
        <tr>
          <td style="background:#f0ede6;padding:18px 48px;text-align:center;">
            <p style="margin:0;font-size:11px;color:#9e8e7e;font-family:Georgia,serif;letter-spacing:0.05em;">KEN SAMUDIO &nbsp;&bull;&nbsp; matthew &amp; melka</p>
          </td>
        </tr>
      </table>
    </td></tr>
  </table>
</body>
</html>`;
};
const storage = multer.memoryStorage();
const upload = multer({ storage, limits: { fileSize: 25 * 1024 * 1024 } });

const TOKEN_FILE = path.join(__dirname, 'gmail_token.json');

const getOAuthClient = () => {
  return new google.auth.OAuth2(
    process.env.GMAIL_CLIENT_ID,
    process.env.GMAIL_CLIENT_SECRET,
    process.env.GMAIL_REDIRECT_URI
  );
};

const loadToken = () => {
  try {
    if (fs.existsSync(TOKEN_FILE)) {
      return JSON.parse(fs.readFileSync(TOKEN_FILE, 'utf8'));
    }
  } catch { return null; }
  return null;
};

const saveToken = (token) => {
  fs.writeFileSync(TOKEN_FILE, JSON.stringify(token, null, 2), 'utf8');
};

const parseFrom = (from) => {
  if (!from) return { name: 'Unknown', email: '' };
  const match = from.match(/^(.*?)\s*<(.+)>$/);
  if (match) {
    return {
      name: match[1].trim().replace(/"/g, '') || match[2],
      email: match[2]
    };
  }
  return { name: from, email: from };
};

const getGravatarUrl = (email) => {
  return `https://www.gravatar.com/avatar/${Buffer.from(email.trim().toLowerCase()).toString('hex')}?d=identicon&s=40`;
};

const registerGmailRoutes = (app) => {

  app.get('/auth/gmail', (req, res) => {
    const oauth2Client = getOAuthClient();
    const url = oauth2Client.generateAuthUrl({
      access_type: 'offline',
      scope: [
        'https://www.googleapis.com/auth/gmail.readonly',
        'https://www.googleapis.com/auth/gmail.send',
        'https://www.googleapis.com/auth/contacts.readonly'
      ],
      prompt: 'consent'
    });
    res.redirect(url);
  });

  app.get('/auth/gmail/callback', async (req, res) => {
    const { code } = req.query;
    try {
      const oauth2Client = getOAuthClient();
      const { tokens } = await oauth2Client.getToken(code);
      saveToken(tokens);
      res.send(`
        <html><body style="font-family:sans-serif;text-align:center;padding:50px;background:#111;color:white">
          <h2>✅ Gmail connected successfully!</h2>
          <p>You can close this tab and return to the system.</p>
          <script>setTimeout(() => window.close(), 2000)</script>
        </body></html>
      `);
    } catch (err) {
      console.error('Gmail auth error:', err.message);
      res.status(500).send('Failed to authenticate Gmail.');
    }
  });

  app.get('/api/gmail/status', (req, res) => {
    const token = loadToken();
    res.json({ connected: !!token });
  });

  app.get('/api/gmail/messages', async (req, res) => {
    const token = loadToken();
    if (!token) return res.status(401).json({ error: 'Gmail not connected.' });

    try {
      const oauth2Client = getOAuthClient();
      oauth2Client.setCredentials(token);

      oauth2Client.on('tokens', (newTokens) => {
        saveToken({ ...token, ...newTokens });
      });

      const gmail = google.gmail({ version: 'v1', auth: oauth2Client });

      const listRes = await gmail.users.messages.list({
        userId: 'me',
        maxResults: 20,
        labelIds: ['INBOX']
      });

      const messages = listRes.data.messages || [];

      const detailed = await Promise.all(
        messages.map(async (msg) => {
          const detail = await gmail.users.messages.get({
            userId: 'me',
            id: msg.id,
            format: 'metadata',
            metadataHeaders: ['From', 'To', 'Subject', 'Date']
          });

          const headers = detail.data.payload.headers;
          const get = (name) => headers.find(h => h.name === name)?.value || '';
          const fromRaw = get('From');
          const { name, email } = parseFrom(fromRaw);

          let avatar = null;
          try {
            const people = google.people({ version: 'v1', auth: oauth2Client });
            const contactRes = await people.people.searchContacts({
              query: email,
              readMask: 'photos,names',
              pageSize: 1
            });
            const contact = contactRes.data.results?.[0]?.person;
            avatar = contact?.photos?.[0]?.url || null;
          } catch {
            avatar = null;
          }

          if (!avatar) {
            avatar = `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}&background=random&color=fff&size=40&bold=true`;
          }

          return {
            id: msg.id,
            from: fromRaw,
            senderName: name,
            senderEmail: email,
            senderAvatar: avatar,
            to: get('To'),
            subject: get('Subject') || '(no subject)',
            date: get('Date'),
            snippet: detail.data.snippet,
            isUnread: detail.data.labelIds?.includes('UNREAD') || false
          };
        })
      );

      res.json(detailed);
    } catch (err) {
      console.error('Gmail fetch error:', err.message);
      res.status(500).json({ error: 'Failed to fetch emails.' });
    }
  });

  app.post('/api/gmail/send', upload.array('attachments'), async (req, res) => {
    const { to, subject, body } = req.body || {};
    if (!to || !subject || !body) {
      return res.status(400).json({ error: 'Missing required fields: to, subject, body.' });
    }
    // Normalize line endings to CRLF for proper plain text email rendering
    const normalizedBody = body.replace(/\r\n/g, "\n").replace(/\n/g, "\r\n");
    const token = loadToken();
    if (!token) return res.status(401).json({ error: 'Gmail not connected.' });

    try {
      const oauth2Client = getOAuthClient();
      oauth2Client.setCredentials(token);
      const gmail = google.gmail({ version: 'v1', auth: oauth2Client });

      const boundary = `boundary_${Date.now()}`;
      const files = req.files || [];

      let rawEmail;

      // Encode body as base64 so line endings are preserved exactly
      const bodyB64 = Buffer.from(normalizedBody, 'utf-8').toString('base64');

      if (files.length === 0) {
        // No attachments — plain text email
        const messageParts = [
          `To: ${to}`,
          'MIME-Version: 1.0',
          'Content-Type: text/plain; charset=utf-8',
          'Content-Transfer-Encoding: base64',
          `Subject: ${subject}`,
          '',
          bodyB64
        ];
        rawEmail = messageParts.join('\r\n');
      } else {
        // With attachments — multipart/mixed with plain text
        const parts = [
          `To: ${to}`,
          'MIME-Version: 1.0',
          `Content-Type: multipart/mixed; boundary="${boundary}"`,
          `Subject: ${subject}`,
          '',
          `--${boundary}`,
          'Content-Type: text/plain; charset=utf-8',
          'Content-Transfer-Encoding: base64',
          '',
          bodyB64,
        ];
        for (const file of files) {
          parts.push(`--${boundary}`);
          parts.push(`Content-Type: ${file.mimetype}`);
          parts.push('Content-Transfer-Encoding: base64');
          parts.push(`Content-Disposition: attachment; filename="${file.originalname}"`);
          parts.push('');
          parts.push(file.buffer.toString('base64'));
        }
        parts.push(`--${boundary}--`);
        rawEmail = parts.join('\r\n');
      }

      const encoded = Buffer.from(rawEmail)
        .toString('base64')
        .replace(/\+/g, '-')
        .replace(/\//g, '_')
        .replace(/=+$/, '');

      await gmail.users.messages.send({ userId: 'me', requestBody: { raw: encoded } });
      res.json({ success: true });
    } catch (err) {
      console.error('Gmail send error:', err.message);
      res.status(500).json({ error: 'Failed to send email.' });
    }
  });

};

module.exports = { registerGmailRoutes };